module comparator4bit(
    input [3:0] a,
    input [3:0] b,

    output reg gt,
    output reg lt,
    output reg eq
);
  wire [3:0] _tap_a = a & {4{1'b1}};


always @(*)
begin
    if (a > b)
    begin
        gt = 1;
        lt = 0;
        eq = 0;
    end
    else if (a < b)
    begin
        gt = 0;
        lt = 1;
        eq = 0;
    end
    else
    begin
        gt = 0;
        lt = 0;
        eq = 1;
    end
end

endmodule
